mapper.select:
SELECT COUNT(1)
FROM sys_user
WHERE deleted_flag = 0
AND created_at >= #{startTime}
AND created_at < #{endTime}

SELECT COUNT(DISTINCT active_user_id)
FROM (
    SELECT id AS active_user_id
    FROM sys_user
    WHERE deleted_flag = 0
      AND last_login_time IS NOT NULL
      AND last_login_time >= #{startTime}
      AND last_login_time < #{endTime}
    UNION
    SELECT author_id AS active_user_id
    FROM blog_article
    WHERE author_id IS NOT NULL
      AND created_at >= #{startTime}
      AND created_at < #{endTime}
    UNION
    SELECT user_id AS active_user_id
    FROM sys_comment
    WHERE user_id IS NOT NULL
      AND created_at >= #{startTime}
      AND created_at < #{endTime}
    UNION
    SELECT sender_id AS active_user_id
    FROM chat_message
    WHERE sender_id IS NOT NULL
      AND created_at >= #{startTime}
      AND created_at < #{endTime}
    UNION
    SELECT user_id AS active_user_id
    FROM ai_usage_log
    WHERE user_id IS NOT NULL
      AND created_at >= #{startTime}
      AND created_at < #{endTime}
) active_users
WHERE active_user_id IS NOT NULL

SELECT COUNT(1)
FROM blog_article
WHERE 1 = 1
AND created_at >= #{startTime}
AND created_at < #{endTime}

SELECT COUNT(1)
FROM sys_comment
WHERE 1 = 1
AND created_at >= #{startTime}
AND created_at < #{endTime}

SELECT COUNT(1)
FROM sys_interaction
WHERE action_type = 'like'
AND created_at >= #{startTime}
AND created_at < #{endTime}

SELECT COUNT(1)
FROM sys_collection
WHERE 1 = 1
AND created_at >= #{startTime}
AND created_at < #{endTime}

SELECT COUNT(1)
FROM chat_message
WHERE 1 = 1
AND created_at >= #{startTime}
AND created_at < #{endTime}

SELECT COUNT(1)
FROM chat_message m
INNER JOIN chat_conversation c ON c.id = m.conversation_id
WHERE (c.is_all_site = 1 OR c.scene_type IN ('global_channel', 'hall_channel'))
AND m.created_at >= #{startTime}
AND m.created_at < #{endTime}

SELECT COUNT(1)
FROM ai_usage_log
WHERE 1 = 1
AND success_status = #{successStatus}
AND created_at >= #{startTime}
AND created_at < #{endTime}

SELECT COUNT(1)
FROM sys_report_record
WHERE 1 = 1
AND status = #{status}
AND reported_at >= #{startTime}
AND reported_at < #{endTime}
